--旅人actor
local baseActor = require "actor.BaseActor"

TravellerActor = class("TravellerActor", baseActor)

function TravellerActor:ctor(id)
    local config = TravellerConfig:getConfigById(id)
    if not config then
        return {}
    end
    self.startPos = config.startPos
    self.endPos = config.endPos
    self.randomPoolId = config.randomPoolId
    self.randomPoolParams = config.randomPoolParams
    self.goodsList = {}
    self:randomTraveller(config.yaw, config.actor, config.name)
end

function TravellerActor:randomTraveller(yaw, actor, name)
    self.goodsList = {}
    self.super:ctor(self:randomPoint(self.startPos, self.endPos), yaw, actor or "", name, "", self)
    self.goodsList = GoodsPoolManager:randomGoods(self.randomPoolId, self.randomPoolParams)
end

function TravellerActor:randomPoint(startPos, endPos)
    local x = math.random(tonumber(startPos[1]), tonumber(endPos[1]))
    local y = math.random(tonumber(startPos[2]), tonumber(endPos[2]))
    local z = math.random(tonumber(startPos[3]), tonumber(endPos[3]))
    return VectorUtil.newVector3(x, y, z)
end

function TravellerActor:clickedActor(player)
    player.storeEntityId = self.entityId
    GamePacketSender:sendWalkingDeadShowStoreByTraveller(player.rakssid, self.goodsList)
    player:syncVipInfo()
end

function TravellerActor:dayAlternatesWithNight(isDay)
    if isDay then
        self:destroyActor()
        self.goodsList = {}
    else
        self:randomTraveller(self.yaw, self.actorName, self.name)
    end
end

function TravellerActor:getGoodsCount(goodsId)
    for _, goods in pairs(self.goodsList) do
        if goodsId == goods.goodsId then
            return goods.limit
        end
    end
    return 0
end

function TravellerActor:onPlayerBuyGoods(goodsId, count)
    local limit = 0
    for _, goods in pairs(self.goodsList) do
        if goodsId == goods.goodsId then
            goods.limit = math.max(goods.limit - count, 0)
            limit = goods.limit
            break
        end
    end
    GamePacketSender:sendWalkingDeadUpdateGoods(goodsId, limit)
end
